'use strict';

/**
* Return a new ndarray filled with linearly spaced numeric elements which increment by 1 starting from a specified value along one or more ndarray dimensions.
*
* @module @stdlib/blas/ext/unitspace
*
* @example
* import unitspace from '@stdlib/blas/ext/unitspace';
*
* var out = unitspace( [ 4 ], 1.0 );
* // returns <ndarray>[ 1.0, 2.0, 3.0, 4.0 ]
*
* @example
* import zeros from '@stdlib/ndarray/zeros';
* import unitspace from '@stdlib/blas/ext/unitspace';
*
* var x = zeros( [ 4 ] );
* // returns <ndarray>[ 0.0, 0.0, 0.0, 0.0 ]
*
* var out = unitspace.assign( x, 1.0 );
* // returns <ndarray>[ 1.0, 2.0, 3.0, 4.0 ]
*
* var bool = ( out === x );
* // returns true
*/

// MODULES //

import setReadOnly from '@stdlib/utils/define-nonenumerable-read-only-property';
import main from './main.js';
import assign from './assign.js';


// MAIN //

setReadOnly( main, 'assign', assign );


// EXPORTS //

export default main;

// exports: { "assign": "main.assign" }
