'use strict';

// MODULES //

import ndarraylike2scalar from '@stdlib/ndarray/base/ndarraylike2scalar';
import numelDimension from '@stdlib/ndarray/base/numel-dimension';
import getStride from '@stdlib/ndarray/base/stride';
import getOffset from '@stdlib/ndarray/base/offset';
import getData from '@stdlib/ndarray/base/data-buffer';
import { ndarray as strided } from './../../../../../ext/base/ssort';


// MAIN //

/**
* Sorts a one-dimensional single-precision floating-point ndarray.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a zero-dimensional ndarray specifying the sort order.
*
* -   When the sort order is less than zero, the input ndarray is sorted in **decreasing** order. When the sort order is greater than zero, the input ndarray is sorted in **increasing** order. When the sort order is equal to zero, the input ndarray is left unchanged.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {ndarray} input ndarray
*
* @example
* import Float32Vector from '@stdlib/ndarray/vector/float32';
* import scalar2ndarray from '@stdlib/ndarray/from-scalar';
*
* var x = new Float32Vector( [ 1.0, -2.0, 3.0, -4.0 ] );
*
* var order = scalar2ndarray( 1.0, {
*    'dtype': 'generic'
* });
*
* var out = ssort( [ x, order ] );
* // returns <ndarray>[ -4.0, -2.0, 1.0, 3.0 ]
*/
function ssort( arrays ) {
	var order;
	var x;

	x = arrays[ 0 ];
	order = arrays[ 1 ];

	strided( numelDimension( x, 0 ), ndarraylike2scalar( order ), getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len

	return x;
}


// EXPORTS //

export default ssort;
